import * as React from 'react';
import clsx from 'clsx';
import { RcMenuContext } from './context/MenuContext';
import { useMeasure } from './context/PathContext';

export interface RcDividerProps {
  className?: string;
  style?: React.CSSProperties;
}

export default function RcDivider({ className, style }: RcDividerProps) {
  const { prefixCls } = React.useContext(RcMenuContext)!;
  const measure = useMeasure();

  if (measure) {
    return null;
  }

  return <li className={clsx(`${prefixCls}-item-divider`, className)} style={style} />;
}
